from typing import Any, Dict, List, Optional, Union, cast

from fastapi.exceptions import HTTPException
from fastapi.openapi.models import OAuth2 as OAuth2Model
from fastapi.openapi.models import OAuthFlows as OAuthFlowsModel
from fastapi.param_functions import Form
from fastapi.security.base import SecurityBase
from fastapi.security.utils import get_authorization_scheme_param
from starlette.requests import Request
from starlette.status import HTTP_401_UNAUTHORIZED, HTTP_403_FORBIDDEN

# TODO: import from typing when deprecating Python 3.9
from typing_extensions import Annotated, Doc  # type: ignore [attr-defined]


class OAuth2PasswordRequestForm:
    """
    Dependency class to parse OAuth2 password request form fields.

    This collects the standard OAuth2 password grant fields from form data:
    - grant_type (optional, typically "password")
    - username
    - password
    - scope (space-separated string of scopes)
    - client_id (optional)
    - client_secret (optional)

    It exposes .username, .password, .scopes (as a list), .grant_type,
    .client_id and .client_secret for use in your dependencies.
    """

    def __init__(
        self,
        *,
        grant_type: Annotated[
            Union[str, None],
            Form(pattern="password"),
            Doc(
                """
                The OAuth2 spec says it is required and MUST be the fixed string
                "password". Nevertheless, this dependency class is permissive and
                allows not passing it. If you want to enforce it, use instead the
                `OAuth2PasswordRequestFormStrict` dependency.
                """
            ),
        ] = None,
        username: Annotated[
            str,
            Form(),
            Doc(
                """
                `username` string. The OAuth2 spec requires the exact field name
                `username`.
                """
            ),
        ] = Form(...),
        password: Annotated[
            str,
            Form(),
            Doc(
                """
                `password` string. The OAuth2 spec requires the exact field name
                `password`.
                """
            ),
        ] = Form(...),
        scope: Annotated[
            str,
            Form(),
            Doc(
                """
                A single string with actually several scopes separated by spaces. Each
                scope is also a string.

                For example, a single string with:

                '''python
                "items:read items:write users:read profile openid"
                '''`

                would represent the scopes:

                * `items:read`
                * `items:write`
                * `users:read`
                * `profile`
                * `openid`
                """
            ),
        ] = Form(""),
        client_id: Annotated[
            Optional[str],
            Form(),
        ] = Form(None),
        client_secret: Annotated[
            Optional[str],
            Form(),
        ] = Form(None),
    ) -> None:
        """
        Initialize the OAuth2PasswordRequestForm dependency.

        Parameters:
        - grant_type: Optional grant type value from the form.
        - username: Username from the form (required).
        - password: Password from the form (required).
        - scope: Space-separated scopes string.
        - client_id: Optional client_id from the form.
        - client_secret: Optional client_secret from the form.
        """
        self.username = username
        self.password = password
        self.scopes: List[str] = scope.split() if scope else []
        self.grant_type = grant_type
        self.client_id = client_id
        self.client_secret = client_secret


class OAuth2PasswordRequestFormStrict:
    """
    Dependency class to parse OAuth2 password request form fields, enforcing
    that the grant_type is provided and matches "password".

    Same as OAuth2PasswordRequestForm but stricter about the grant_type field.
    """

    def __init__(
        self,
        *,
        grant_type: Annotated[
            str,
            Form(pattern="password"),
            Doc(
                """
                The OAuth2 spec says it is required and MUST be the fixed string
                "password". This strict variant enforces it by making it required.
                """
            ),
        ] = Form(...),
        username: Annotated[
            str,
            Form(),
            Doc(
                """
                `username` string. The OAuth2 spec requires the exact field name
                `username`.
                """
            ),
        ] = Form(...),
        password: Annotated[
            str,
            Form(),
            Doc(
                """
                `password` string. The OAuth2 spec requires the exact field name
                `password`.
                """
            ),
        ] = Form(...),
        scope: Annotated[
            str,
            Form(),
            Doc(
                """
                A single string with several scopes separated by spaces.
                """
            ),
        ] = Form(""),
        client_id: Annotated[
            Optional[str],
            Form(),
        ] = Form(None),
        client_secret: Annotated[
            Optional[str],
            Form(),
        ] = Form(None),
    ) -> None:
        """
        Initialize the strict OAuth2PasswordRequestForm dependency.

        Parameters:
        - grant_type: Required grant type value from the form (must match "password").
        - username: Username from the form (required).
        - password: Password from the form (required).
        - scope: Space-separated scopes string.
        - client_id: Optional client_id from the form.
        - client_secret: Optional client_secret from the form.
        """
        self.username = username
        self.password = password
        self.scopes: List[str] = scope.split() if scope else []
        self.grant_type = grant_type
        self.client_id = client_id
        self.client_secret = client_secret


class OAuth2(SecurityBase):
    """
    Base class for OAuth2 schemes. Implements reading the Bearer token from
    the Authorization header and some common behaviors.
    """

    def __init__(
        self,
        flows: OAuthFlowsModel,
        *,
        scheme_name: Optional[str] = None,
        scopes: Optional[Dict[str, str]] = None,
        description: Optional[str] = None,
        auto_error: bool = True,
    ) -> None:
        """
        Initialize the OAuth2 scheme.

        Parameters:
        - flows: OAuthFlowsModel describing the available OAuth2 flows.
        - scheme_name: Optional name of the security scheme.
        - scopes: Optional mapping of scope names to descriptions.
        - description: Optional description for the scheme.
        - auto_error: Whether to automatically raise HTTP errors when authentication fails.
        """
        super().__init__(scheme_name=scheme_name, scopes=scopes, description=description, auto_error=auto_error)
        self.model = OAuth2Model(flows=flows, description=description)

    async def __call__(self, request: Request) -> Optional[str]:
        """
        Extract and validate a Bearer token from the Authorization header.

        Returns the token string when valid, or raises/returns None depending on auto_error.
        """
        authorization: str = request.headers.get("Authorization") or ""
        scheme, param = get_authorization_scheme_param(authorization)
        if not authorization or scheme.lower() != "bearer":
            if self.auto_error:
                raise HTTPException(
                    status_code=HTTP_401_UNAUTHORIZED,
                    detail="Not authenticated",
                    headers={"WWW-Authenticate": "Bearer"},
                )
            else:
                return None
        return param


class OAuth2PasswordBearer(OAuth2):
    """
    OAuth2 scheme that uses the "password" flow and expects a token to be provided
    as a Bearer token in the Authorization header.
    """

    def __init__(
        self,
        tokenUrl: str,
        *,
        scheme_name: Optional[str] = None,
        scopes: Optional[Dict[str, str]] = None,
        description: Optional[str] = None,
        auto_error: bool = True,
    ) -> None:
        """
        Initialize the OAuth2PasswordBearer scheme.

        Parameters:
        - tokenUrl: The URL to use for getting the token (required by the OpenAPI schema).
        - scheme_name: Optional name of the security scheme.
        - scopes: Optional mapping of scope names to descriptions.
        - description: Optional description for the scheme.
        - auto_error: Whether to automatically raise HTTP errors when authentication fails.
        """
        flows = OAuthFlowsModel(password={"tokenUrl": tokenUrl, "scopes": scopes or {}})
        super().__init__(flows=flows, scheme_name=scheme_name, scopes=scopes, description=description, auto_error=auto_error)


class OAuth2AuthorizationCodeBearer(OAuth2):
    """
    OAuth2 scheme for the authorization code flow. Expects Bearer tokens in the Authorization header.
    """

    def __init__(
        self,
        authorizationUrl: str,
        tokenUrl: str,
        *,
        scheme_name: Optional[str] = None,
        scopes: Optional[Dict[str, str]] = None,
        description: Optional[str] = None,
        auto_error: bool = True,
    ) -> None:
        """
        Initialize the OAuth2AuthorizationCodeBearer scheme.

        Parameters:
        - authorizationUrl: The authorization URL for the OAuth2 flow.
        - tokenUrl: The token URL for the OAuth2 flow.
        - scheme_name: Optional name of the security scheme.
        - scopes: Optional mapping of scope names to descriptions.
        - description: Optional description for the scheme.
        - auto_error: Whether to automatically raise HTTP errors when authentication fails.
        """
        flows = OAuthFlowsModel(
            authorizationCode={"authorizationUrl": authorizationUrl, "tokenUrl": tokenUrl, "scopes": scopes or {}}
        )
        super().__init__(flows=flows, scheme_name=scheme_name, scopes=scopes, description=description, auto_error=auto_error)


class OAuth2PasswordBearerCookie(OAuth2):
    """
    Variant of OAuth2PasswordBearer that will also attempt to extract the token
    from a cookie named 'access_token' if the Authorization header is not present.

    This is not part of FastAPI core but provided here for convenience.
    """

    def __init__(
        self,
        tokenUrl: str,
        *,
        cookie_name: str = "access_token",
        scheme_name: Optional[str] = None,
        scopes: Optional[Dict[str, str]] = None,
        description: Optional[str] = None,
        auto_error: bool = True,
    ) -> None:
        """
        Initialize the OAuth2PasswordBearerCookie scheme.

        Parameters:
        - tokenUrl: The URL to use for getting the token (required by the OpenAPI schema).
        - cookie_name: Name of the cookie to check when Authorization header is absent.
        - scheme_name: Optional name of the security scheme.
        - scopes: Optional mapping of scope names to descriptions.
        - description: Optional description for the scheme.
        - auto_error: Whether to automatically raise HTTP errors when authentication fails.
        """
        self.cookie_name = cookie_name
        flows = OAuthFlowsModel(password={"tokenUrl": tokenUrl, "scopes": scopes or {}})
        super().__init__(flows=flows, scheme_name=scheme_name, scopes=scopes, description=description, auto_error=auto_error)

    async def __call__(self, request: Request) -> Optional[str]:
        """
        Attempt to retrieve the token from the Authorization header, falling back
        to a cookie if the header is not present.
        """
        authorization: str = request.headers.get("Authorization") or ""
        scheme, param = get_authorization_scheme_param(authorization)
        if authorization and scheme.lower() == "bearer":
            return param

        # Fallback to cookie
        token = request.cookies.get(self.cookie_name)
        if token:
            return token

        if self.auto_error:
            raise HTTPException(
                status_code=HTTP_401_UNAUTHORIZED,
                detail="Not authenticated",
                headers={"WWW-Authenticate": "Bearer"},
            )
        return None